class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        colors = ['red', 'black']
        row_indices = [0, 2, 4, 6]
        for color in colors:
            for row_index in row_indices:
                if color == 'red':
                    for col_index in range(0, 8, 2):
                        self.board[row_index][col_index] = Piece(color, (row_index, col_index))
