from game_board import Board, Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def print_board(self):
        self.board.print_board()

    def move_piece(self, start_pos, end_pos):
        # Move a piece from start position to end position
        piece = self.board.board[start_pos[0]][start_pos[1]]
        if piece:
            self.board.board[end_pos[0]][end_pos[1]] = piece
            self.board.board[start_pos[0]][start_pos[1]] = None
            piece.position = end_pos

    def is_valid_move(self, start_pos, end_pos):
        # Check if the move is valid
        piece = self.board.board[start_pos[0]][start_pos[1]]
        if piece and piece.color == self.current_player:
            return True
        return False

    def make_move(self, move_str):
        # Parse the move string and make a move
        start_pos, end_pos = move_str.split('-')
        start_pos = (int(start_pos[0]) - 1, int(start_pos[2]) - 1)
        end_pos = (int(end_pos[0]) - 1, int(end_pos[2]) - 1)
        if self.is_valid_move(start_pos, end_pos):
            self.move_piece(start_pos, end_pos)
            self.switch_player()
        else:
            print("Invalid move. Try again.")

    def switch_player(self):
        # Switch the current player
        if self.current_player == 'red':
            self.current_player = 'black'
        else:
            self.current_player = 'red'

# Example usage
